import{_ as r,r as i,o as a,c as n,b as e,d as t,e as c,a as s}from"./app-2a089349.js";const l={},p=s('<h1 id="create-subscription-prices" tabindex="-1"><a class="header-anchor" href="#create-subscription-prices" aria-hidden="true">#</a> Create Subscription Prices</h1><h3 id="overview" tabindex="-1"><a class="header-anchor" href="#overview" aria-hidden="true">#</a> <strong>Overview</strong></h3><p>Stripe allows you to create subscription prices for your subscription shortcode. This way, you can create multiple subscribe buttons with different prices or Stripe Plan options in the Register form.</p><p>If you have existing subscription prices, you can simply <a href="/docs-v3/um-stripe/article/1846-import-existing-subscription-prices-from-your-stripe-account">import them from the stripe settings</a> but if you have not created any prices yet, do the following steps below:</p>',4),d={href:"https://dashboard.stripe.com/",target:"_blank",rel:"noopener noreferrer"},g=e("strong",null,"+More'",-1),u=e("strong",null,"Product Catalog",-1),h=e("img",{src:"https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba4e817507a5314cbc0c0e/file-egnNmwOvIM.png",alt:""},null,-1),m=s('<li>On the Product Catalog page, Click the &quot; + <strong>Add product</strong>&quot; button to display the form. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba4fea7507a5314cbc0c11/file-bP7KCBfysm.png" alt=""></li><li>Add the <strong>&quot;Name</strong>&quot;, &quot;<strong>Description(optional)</strong>&quot; and &quot;<strong>Image(optional)</strong> of your product<strong>.</strong> <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba7606ed989b06acd56691/file-WCfjzlMhac.png" alt=""></li><li>In the Price Information, the UM Stripe module supports <strong>Recurring Prices</strong> and <strong>One-time</strong> <strong>Prices</strong> as the Pricing Models <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba793d7507a5314cbc0c62/file-tMV9ENAHcp.png" alt=""></li><li>Suppose you have selected Recurring as your pricing model. In that case, you can choose the following <strong>Billing Period</strong> from the drop-down menu: <strong>Daily, Weekly, Monthly, Every 3 months,</strong> <strong>Every 6 months,</strong> <strong>Yearly,</strong> &amp; <strong>Custom. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba8804a7493b27a932f81b/file-j2mRHUuvUp.png" alt=""></strong></li><li>Create multiple pricing options per product by clicking the <strong>&#39;+Add another price&#39;</strong> button. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba89a7ed989b06acd566ba/file-uRXanAH3MX.png" alt=""></li><li>For an alternative pricing structure, you have the flexibility to choose the <strong>&#39;One-time&#39;</strong> option. This empowers your users to decide between recurring or one-time payments for their purchases or subscriptions. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba8bc3ed989b06acd566c2/file-R5um8DHFr0.png" alt=""></li><li>After saving the product, proceed to <a href="/docs-v3/um-stripe/article/1846-import-existing-subscription-prices-from-your-stripe-account">import prices from your Stripe Account</a> by navigating to <strong>wp-admin &gt; Ultimate Member &gt; Settings &gt; Extensions &gt; Stripe.</strong></li><li>Once the import process is complete, the newly created prices will appear in the Stripe Plans form at <strong>WP-Admin &gt; Ultimate Member &gt; Stripe Plans</strong>. Simply hover your mouse over the desired Stripe Plan and click on <strong>&#39;Edit&#39;.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba9389ed989b06acd566d4/file-AZiexNBIzm.png" alt=""></strong></li><li>You&#39;ll find the product type and associated price you established with Stripe listed under <strong>Subscription Price</strong>. These details are locked to prevent any conflicts. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba968d7507a5314cbc0ca1/file-X5ztcIylse.png" alt=""></li><li>The corresponding &#39; <strong>one-time&#39;</strong> price configured in Stripe will be showcased in the Subscription Price field.</li>',10),b=e("p",null,[e("strong",null,[t("EXT: "),e("a",{href:"/docs-v3/um-stripe/article/1616-stripe-shortcodes-reference"},"SHORTCODE REFERENCE")])],-1);function f(y,_){const o=i("ExternalLinkIcon");return a(),n("div",null,[p,e("ol",null,[e("li",null,[t("To create a new subscription/product price, go to "),e("a",d,[t("https://dashboard.stripe.com/"),c(o)]),t(" and on the side menu, click on the '"),g,t(" tab and click on "),u,t(" under Manage your products "),h]),m]),b])}const v=r(l,[["render",f],["__file","1617-create-subscription-prices.html.vue"]]);export{v as default};
